/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently designed around email (the only channel), but structured
 * to accommodate future channels without restructuring.
 */

import type { NotificationType } from './notification.js';

/**
 * How frequently email notifications are delivered.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary
 * - 'weekly-digest': batch into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Per-user notification preferences.
 */
export interface UserPreferences {
  id: string;
  /** The user this preferences record belongs to */
  userId: string;
  /** Master switch for all email notifications */
  emailEnabled: boolean;
  /** How often email notifications are delivered */
  emailFrequency: EmailFrequency;
  /** Per-category subscription settings — true means subscribed */
  categorySubscriptions: Record<NotificationType, boolean>;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating preferences (userId required, rest optional with defaults).
 */
export interface CreatePreferencesInput {
  userId: string;
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  categorySubscriptions?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Input for updating existing preferences.
 */
export interface UpdatePreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  categorySubscriptions?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Default category subscriptions — all enabled by default.
 */
export const defaultCategorySubscriptions: Record<NotificationType, boolean> = {
  'order-confirmation': true,
  'order-status-update': true,
  'user-welcome': true,
  'user-profile-update': true,
  'system-alert': true,
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      emailEnabled: record['emailEnabled'] as boolean,
      emailFrequency: record['emailFrequency'] as UserPreferences['emailFrequency'],
      categorySubscriptions: JSON.parse(
        record['categorySubscriptions'] as string,
      ) as Record<NotificationType, boolean>,
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.emailEnabled,
      emailFrequency: entity.emailFrequency,
      categorySubscriptions: JSON.stringify(entity.categorySubscriptions),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Service for managing user notification preferences.
 *
 * Provides CRUD operations with sensible defaults.
 * Works with PreferencesRepository for persistence.
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  CreatePreferencesInput,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { defaultCategorySubscriptions } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getByUserId(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating defaults if none exist.
   */
  getOrCreateForUser(userId: string): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return this.create({ userId });
  }

  /**
   * Create notification preferences for a user.
   */
  create(input: CreatePreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      emailEnabled: input.emailEnabled ?? true,
      emailFrequency: input.emailFrequency ?? 'immediate',
      categorySubscriptions: {
        ...defaultCategorySubscriptions,
        ...input.categorySubscriptions,
      },
      createdAt: now,
      updatedAt: now,
    };

    this.repository.save(preferences);
    this.logger.info(`Created preferences for user: ${input.userId}`);
    return preferences;
  }

  /**
   * Update existing preferences for a user.
   */
  update(userId: string, input: UpdatePreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      throw new Error(`No preferences found for user: ${userId}`);
    }

    const updated: UserPreferences = {
      ...existing,
      emailEnabled: input.emailEnabled ?? existing.emailEnabled,
      emailFrequency: input.emailFrequency ?? existing.emailFrequency,
      categorySubscriptions: input.categorySubscriptions
        ? { ...existing.categorySubscriptions, ...input.categorySubscriptions }
        : existing.categorySubscriptions,
      updatedAt: new Date(),
    };

    this.repository.update(existing.id, updated);
    this.logger.info(`Updated preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Check whether a notification should be sent to a user based on their preferences.
   * Returns true if the notification should proceed.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);

    // No preferences = use defaults (all enabled)
    if (!prefs) {
      return true;
    }

    // Master switch
    if (!prefs.emailEnabled) {
      return false;
    }

    // Per-category check
    const subscribed = prefs.categorySubscriptions[notificationType];
    return subscribed !== false;
  }

  /**
   * Delete preferences for a user.
   */
  delete(userId: string): boolean {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      return false;
    }
    return this.repository.delete(existing.id);
  }
}

