import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { defaultCategorySubscriptions } from '../../src/models/user-preferences.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('create', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.create({ userId: 'user-1' });

      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('immediate');
      expect(prefs.categorySubscriptions).toEqual(defaultCategorySubscriptions);
      expect(prefs.id).toBe('pref-0001');
    });

    it('should create preferences with custom settings', () => {
      const prefs = service.create({
        userId: 'user-1',
        emailEnabled: false,
        emailFrequency: 'daily-digest',
        categorySubscriptions: {
          'order-confirmation': false,
        },
      });

      expect(prefs.emailEnabled).toBe(false);
      expect(prefs.emailFrequency).toBe('daily-digest');
      expect(prefs.categorySubscriptions['order-confirmation']).toBe(false);
      expect(prefs.categorySubscriptions['order-status-update']).toBe(true);
    });

    it('should throw if preferences already exist for user', () => {
      service.create({ userId: 'user-1' });
      expect(() => service.create({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const p1 = service.create({ userId: 'user-1' });
      const p2 = service.create({ userId: 'user-2' });

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });
  });

  describe('getByUserId', () => {
    it('should return preferences for existing user', () => {
      service.create({ userId: 'user-1' });
      const prefs = service.getByUserId('user-1');

      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });

    it('should return undefined for non-existent user', () => {
      expect(service.getByUserId('user-99')).toBeUndefined();
    });
  });

  describe('getOrCreateForUser', () => {
    it('should return existing preferences', () => {
      const created = service.create({ userId: 'user-1', emailEnabled: false });
      const fetched = service.getOrCreateForUser('user-1');

      expect(fetched.id).toBe(created.id);
      expect(fetched.emailEnabled).toBe(false);
    });

    it('should create defaults if none exist', () => {
      const prefs = service.getOrCreateForUser('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('immediate');
    });
  });

  describe('update', () => {
    it('should update email enabled setting', () => {
      service.create({ userId: 'user-1' });
      const updated = service.update('user-1', { emailEnabled: false });

      expect(updated.emailEnabled).toBe(false);
      expect(updated.emailFrequency).toBe('immediate'); // unchanged
    });

    it('should update email frequency', () => {
      service.create({ userId: 'user-1' });
      const updated = service.update('user-1', { emailFrequency: 'weekly-digest' });

      expect(updated.emailFrequency).toBe('weekly-digest');
    });

    it('should merge category subscriptions', () => {
      service.create({ userId: 'user-1' });
      const updated = service.update('user-1', {
        categorySubscriptions: { 'order-confirmation': false },
      });

      expect(updated.categorySubscriptions['order-confirmation']).toBe(false);
      expect(updated.categorySubscriptions['order-status-update']).toBe(true);
      expect(updated.categorySubscriptions['system-alert']).toBe(true);
    });

    it('should throw if no preferences exist', () => {
      expect(() => service.update('user-99', { emailEnabled: false })).toThrow(
        'No preferences found for user: user-99',
      );
    });

    it('should update the updatedAt timestamp', () => {
      const created = service.create({ userId: 'user-1' });
      const createdTime = created.updatedAt.getTime();

      // Small delay to ensure different timestamp
      const updated = service.update('user-1', { emailEnabled: false });
      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(createdTime);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (defaults)', () => {
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.create({ userId: 'user-1' });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return false when email is disabled globally', () => {
      service.create({ userId: 'user-1', emailEnabled: false });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return false when category is unsubscribed', () => {
      service.create({
        userId: 'user-1',
        categorySubscriptions: { 'order-confirmation': false },
      });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return true for subscribed category even when others are disabled', () => {
      service.create({
        userId: 'user-1',
        categorySubscriptions: {
          'order-confirmation': false,
          'order-status-update': true,
        },
      });
      expect(service.shouldSendEmail('user-1', 'order-status-update')).toBe(true);
    });

    it('should return false when email disabled even if category is subscribed', () => {
      service.create({
        userId: 'user-1',
        emailEnabled: false,
        categorySubscriptions: { 'order-confirmation': true },
      });
      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
    });
  });

  describe('delete', () => {
    it('should delete existing preferences', () => {
      service.create({ userId: 'user-1' });
      expect(service.delete('user-1')).toBe(true);
      expect(service.getByUserId('user-1')).toBeUndefined();
    });

    it('should return false for non-existent preferences', () => {
      expect(service.delete('user-99')).toBe(false);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);

    const prefsRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(prefsRepo);
    notificationService.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  function makeOrderCreatedEvent(email: string): OrderCreatedEvent {
    return {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: email,
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email,
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };
  }

  it('should send notification when no preferences exist', async () => {
    await eventBus.emit(makeOrderCreatedEvent('alice@example.com'));

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.status).toBe('sent');
  });

  it('should send notification when preferences allow it', async () => {
    preferencesService.create({ userId: 'alice@example.com' });
    await eventBus.emit(makeOrderCreatedEvent('alice@example.com'));

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.status).toBe('sent');
  });

  it('should suppress notification when email is disabled', async () => {
    preferencesService.create({
      userId: 'alice@example.com',
      emailEnabled: false,
    });
    await eventBus.emit(makeOrderCreatedEvent('alice@example.com'));

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.status).toBe('suppressed');
    expect(notifications[0]?.metadata?.suppressedByPreferences).toBe(true);
  });

  it('should suppress notification when category is unsubscribed', async () => {
    preferencesService.create({
      userId: 'alice@example.com',
      categorySubscriptions: { 'order-confirmation': false },
    });
    await eventBus.emit(makeOrderCreatedEvent('alice@example.com'));

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.status).toBe('suppressed');
  });

  it('should not send email when notification is suppressed', async () => {
    preferencesService.create({
      userId: 'alice@example.com',
      emailEnabled: false,
    });
    await eventBus.emit(makeOrderCreatedEvent('alice@example.com'));

    const sentEmails = emailAdapter.getSentEmails();
    expect(sentEmails).toHaveLength(0);
  });

  it('should still work without preferences service set', async () => {
    const freshEventBus = new EventBus();
    const freshService = new NotificationService(freshEventBus);
    freshService.registerAdapter(new EmailAdapter());

    await freshEventBus.emit(makeOrderCreatedEvent('bob@example.com'));

    const notifications = freshService.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.status).toBe('sent');
  });
});

