+/**
+ * Service for managing user notification preferences.
+ *
+ * Provides CRUD operations with sensible defaults.
+ * Works with PreferencesRepository for persistence.
+ */
+
+import type { PreferencesRepository } from '../repositories/preferences.repository.js';
+import type {
+  UserPreferences,
+  CreatePreferencesInput,
+  UpdatePreferencesInput,
+} from '../models/user-preferences.js';
+import type { NotificationType } from '../models/notification.js';
+import { defaultCategorySubscriptions } from '../models/user-preferences.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generatePreferencesId(): string {
+  return `pref-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetPreferencesIdCounter(): void {
+  nextId = 1;
+}
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+
+  constructor(private repository: PreferencesRepository) {}
+
+  /**
+   * Get preferences for a user. Returns undefined if none exist.
+   */
+  getByUserId(userId: string): UserPreferences | undefined {
+    return this.repository.findByUserId(userId);
+  }
+
+  /**
+   * Get preferences for a user, creating defaults if none exist.
+   */
+  getOrCreateForUser(userId: string): UserPreferences {
+    const existing = this.repository.findByUserId(userId);
+    if (existing) {
+      return existing;
+    }
+    return this.create({ userId });
+  }
+
+  /**
+   * Create notification preferences for a user.
+   */
+  create(input: CreatePreferencesInput): UserPreferences {
+    const existing = this.repository.findByUserId(input.userId);
+    if (existing) {
+      throw new Error(`Preferences already exist for user: ${input.userId}`);
+    }
+
+    const now = new Date();
+    const preferences: UserPreferences = {
+      id: generatePreferencesId(),
+      userId: input.userId,
+      emailEnabled: input.emailEnabled ?? true,
+      emailFrequency: input.emailFrequency ?? 'immediate',
+      categorySubscriptions: {
+        ...defaultCategorySubscriptions,
+        ...input.categorySubscriptions,
+      },
+      createdAt: now,
+      updatedAt: now,
+    };
+
+    this.repository.save(preferences);
+    this.logger.info(`Created preferences for user: ${input.userId}`);
+    return preferences;
+  }
+
+  /**
+   * Update existing preferences for a user.
+   */
+  update(userId: string, input: UpdatePreferencesInput): UserPreferences {
+    const existing = this.repository.findByUserId(userId);
+    if (!existing) {
+      throw new Error(`No preferences found for user: ${userId}`);
+    }
+
+    const updated: UserPreferences = {
+      ...existing,
+      emailEnabled: input.emailEnabled ?? existing.emailEnabled,
+      emailFrequency: input.emailFrequency ?? existing.emailFrequency,
+      categorySubscriptions: input.categorySubscriptions
+        ? { ...existing.categorySubscriptions, ...input.categorySubscriptions }
+        : existing.categorySubscriptions,
+      updatedAt: new Date(),
+    };
+
+    this.repository.update(existing.id, updated);
+    this.logger.info(`Updated preferences for user: ${userId}`);
+    return updated;
+  }
+
+  /**
+   * Check whether a notification should be sent to a user based on their preferences.
+   * Returns true if the notification should proceed.
+   */
+  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
+    const prefs = this.repository.findByUserId(userId);
+
+    // No preferences = use defaults (all enabled)
+    if (!prefs) {
+      return true;
+    }
+
+    // Master switch
+    if (!prefs.emailEnabled) {
+      return false;
+    }
+
+    // Per-category check
+    const subscribed = prefs.categorySubscriptions[notificationType];
+    return subscribed !== false;
+  }
+
+  /**
+   * Delete preferences for a user.
+   */
+  delete(userId: string): boolean {
+    const existing = this.repository.findByUserId(userId);
+    if (!existing) {
+      return false;
+    }
+    return this.repository.delete(existing.id);
+  }
+}

